walker ReleaseAudit {
    has visited: int = 0;
    has total_cost: int = 0;

    def record(cost: int) {
        self.visited += 1;
        self.total_cost += cost;
    }
}

def total_cost(services: list[Service]) -> int {
    total: int = 0;
    for svc in services {
        total += svc.cost;
    }
    return total;
}

